public static long binomialCoefficient(final int n, final int k) {
        if (n < k) {
            throw new IllegalArgumentException(
                "must have n >= k for binomial coefficient (n,k)");
        }
        if (n < 0) {
            throw new IllegalArgumentException(
                "must have n >= 0 for binomial coefficient (n,k)");
        }
        if ((n == k) || (k == 0)) {
            return 1;
        }
        if ((k == 1) || (k == n - 1)) {
            return n;
        }

        // Use symmetry for large k
        int kUse = k;
        if (k > n / 2) {
            kUse = n - k;
        }

        if (n <= 61) {
            // For n <= 61, the naive implementation cannot overflow.
            long result = 1;
            for (int i = 1; i <= kUse; i++) {
                result = result * (n - kUse + i) / i;
            }
            return result;
        }

        if (n <= 66) {
            // For n > 61 but n <= 66, the result cannot overflow,
            // but we must take care not to overflow intermediate values.
            long result = 1;
            for (int i = 1; i <= kUse; i++) {
                long d = gcd(i, n - kUse + i);
                result = (result / (i / d)) * ((n - kUse + i) / d);
            }
            return result;
        }

        // For n > 66, a result overflow might occur, so we check
        // the multiplication, taking care to not overflow
        // unnecessary.
        long result = 1;
        for (int i = 1; i <= kUse; i++) {
            long d = gcd(i, n - kUse + i);
            result = mulAndCheck(result / (i / d), (n - kUse + i) / d);
        }

        return result;
    }

public static double binomialCoefficientDouble(final int n, final int k) {
        return Math.floor(Math.exp(binomialCoefficientLog(n, k)) + 0.5);
    }

public static double binomialCoefficientLog(final int n, final int k) {
        if (n < k) {
            throw new IllegalArgumentException(
                "must have n >= k for binomial coefficient (n,k)");
        }
        if (n < 0) {
            throw new IllegalArgumentException(
                "must have n >= 0 for binomial coefficient (n,k)");
        }
        if ((n == k) || (k == 0)) {
            return 0;
        }
        if ((k == 1) || (k == n - 1)) {
            return Math.log((double) n);
        }

        double logSum = 0;

        for (int i = k + 1; i <= n; i++) {
            logSum += Math.log((double)i);
        }

        for (int i = 2; i <= n - k; i++) {
            logSum -= Math.log((double)i);
        }

        return logSum;      
    }

private static long gcd(long a, long b) {
        long absA = Math.abs(a);
        long absB = Math.abs(b);
        while (absB != 0) {
            long temp = absB;
            absB = absA % absB;
            absA = temp;
        }
        return absA;
    }

private static long mulAndCheck(long a, long b) {
        if (a == 0 || b == 0) {
            return 0;
        }
        if (a > 0) {
            if (b > 0) {
                if (a > Long.MAX_VALUE / b) {
                    throw new ArithmeticException("result too large to represent in a long integer");
                }
            } else {
                if (b < Long.MIN_VALUE / a) {
                    throw new ArithmeticException("result too large to represent in a long integer");
                }
            }
        } else {
            if (b > 0) {
                if (a < Long.MIN_VALUE / b) {
                    throw new ArithmeticException("result too large to represent in a long integer");
                }
            } else {
                if (a != 0 && b < Long.MAX_VALUE / a) {
                    throw new ArithmeticException("result too large to represent in a long integer");
                }
            }
        }
        return a * b;
    }
